package com.stockmind.application.factor;
import com.stockmind.domain.factor.*;import java.math.*;import java.util.*;
public record FactorPolicy(String version,InvestmentStyle style,Map<FactorCategory,BigDecimal>weights){public FactorPolicy{weights=Map.copyOf(weights);}/** Returns the versioned category weights for the requested investment style. */public static FactorPolicy of(InvestmentStyle s){Map<FactorCategory,BigDecimal>w=new EnumMap<>(FactorCategory.class);switch(s){case BALANCED->{put(w,25,25,20,15,10,5);}case QUALITY_VALUE->{put(w,35,30,15,10,5,5);}case GROWTH->{put(w,15,20,35,20,10,0);}case DEFENSIVE_INCOME->{put(w,25,30,10,5,10,20);}}return new FactorPolicy("stock-factor-v1",s,w);}private static void put(Map<FactorCategory,BigDecimal>w,int v,int q,int g,int e,int m,int r){w.put(FactorCategory.VALUATION,BigDecimal.valueOf(v));w.put(FactorCategory.QUALITY,BigDecimal.valueOf(q));w.put(FactorCategory.GROWTH,BigDecimal.valueOf(g));w.put(FactorCategory.EXPECTATION_REVISION,BigDecimal.valueOf(e));w.put(FactorCategory.MOMENTUM_RISK,BigDecimal.valueOf(m));w.put(FactorCategory.SHAREHOLDER_RETURN,BigDecimal.valueOf(r));}}
